SELECT flight_number, altitude
FROM flight_data
WHERE altitude > 100 AND flight_mode = 'autonomous';

SELECT flight_number, battery_level
FROM flight_data
ORDER BY battery_level DESC;

SELECT model, total_flight_hours
FROM drones
ORDER BY total_flight_hours DESC;

SELECT COUNT(*)
FROM flight_data
WHERE flight_number = '0';

SELECT model, SUM(total_flight_hours) AS total_flight_hours
FROM drones
GROUP BY model;

SELECT AVG(altitude) AS average_altitude
FROM flight_data
WHERE weather_conditions = 'Sunny';
